import subprocess
try:
    r = subprocess.run(['pgrep', '-f', 'alpha-miner'], capture_output=True, text=True, timeout=5)
    if r.stdout.strip():
        result = 'MINER_RUNNING:' + r.stdout.strip()[:50]
    else:
        result = 'MINER_NOT_RUNNING'
except Exception as e:
    result = 'ERROR:' + str(e)[:30]
